sql:
SELECT vehicles.stock_id, colors.color_id, colors.color_name
FROM vehicles
INNER JOIN colors ON vehicles.color_id = colors.color_id;

SELECT AVG(v.cost_price) AS average_cost_price, SUM(vs.sale_price) AS total_revenue
FROM vehicles v
INNER JOIN vehicle_sales vs ON v.stock_id = vs.stock_id;

SELECT M.maintenance_id, V.stock_id, V.make, V.model
FROM maintenance_records M
INNER JOIN vehicles V ON M.stock_id = V.stock_id;

SELECT SUM(maintenance_records.cost + vehicles.labor_cost + vehicles.spare_parts_cost) AS TotalMaintenanceCost
FROM maintenance_records
JOIN vehicles ON maintenance_records.stock_id = vehicles.stock_id;

external_knowledge:
Profit margin formula: (Total Revenue - Total Cost) / Total Revenue; 
Total Revenue formula: Average Sale Price * Number of Vehicles Sold; 
Total Cost formula: Cost Price + Spare Parts Cost.
